<script lang="ts">import type { ClerkAIConfig, CloudSyncConfig } from '../integrations/custom-ai'; export let cloud:CloudSyncConfig={baseUrl:'',apiToken:''}; export let ai:ClerkAIConfig={endpoint:'',apiKey:'',model:'gpt-4o-mini',maxTokens:2048,transcriptionModel:'gpt-4o-transcribe'}; export let showCloud=true; export let showAI=true; export let onChange:(cloud:CloudSyncConfig,ai:ClerkAIConfig)=>void=()=>undefined;</script>
